import{_ as e,o as t,c as s,a2 as i}from"./chunks/framework.CGYl2SZ_.js";const a=JSON.parse('{"title":"auth monitoring","description":"auth monitoring 页面","frontmatter":{"title":"auth monitoring","description":"auth monitoring 页面"},"headers":[],"relativePath":"tools/automation/auth-monitoring.md","filePath":"tools/automation/auth-monitoring.md"}');const o=e({name:"tools/automation/auth-monitoring.md"},[["render",function(e,a,o,l,d,c){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="身份验证监控" tabindex="-1">身份验证监控 <a class="header-anchor" href="#身份验证监控" aria-label="Permalink to &quot;身份验证监控&quot;">​</a></h1><p>OpenClaw 通过 <code>openclaw models status</code> 暴露 OAuth 过期健康状态。将其用于自动化和告警；脚本是可选的辅助工具，适用于手机工作流。</p><h2 id="推荐方式-cli-检查-便携式" tabindex="-1">推荐方式：CLI 检查（便携式） <a class="header-anchor" href="#推荐方式-cli-检查-便携式" aria-label="Permalink to &quot;推荐方式：CLI 检查（便携式）&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --check</span></span></code></pre></div><p>退出码：</p><ul><li><code>0</code>：正常</li><li><code>1</code>：凭据已过期或缺失</li><li><code>2</code>：即将过期（24小时内）</li></ul><p>这适用于 cron/systemd，无需额外脚本。</p><h2 id="可选脚本-运维-手机工作流" tabindex="-1">可选脚本（运维/手机工作流） <a class="header-anchor" href="#可选脚本-运维-手机工作流" aria-label="Permalink to &quot;可选脚本（运维/手机工作流）&quot;">​</a></h2><p>这些脚本位于 <code>scripts/</code> 目录下，是<strong>可选的</strong>。它们假设可以 SSH 访问网关主机，适用于 systemd + Termux 环境。</p><ul><li><code>scripts/claude-auth-status.sh</code> 现在使用 <code>openclaw models status --json</code> 作为真实来源（如果 CLI 不可用则回退到直接文件读取），因此请将 <code>openclaw</code> 保持在 <code>PATH</code> 中以供定时器使用。</li><li><code>scripts/auth-monitor.sh</code>：cron/systemd 定时器目标；发送告警（ntfy 或手机）。</li><li><code>scripts/systemd/openclaw-auth-monitor.{service,timer}</code>：systemd 用户定时器。</li><li><code>scripts/claude-auth-status.sh</code>：Claude Code + OpenClaw 身份验证检查器（完整/json/简单模式）。</li><li><code>scripts/mobile-reauth.sh</code>：通过 SSH 引导的重新认证流程。</li><li><code>scripts/termux-quick-auth.sh</code>：一键式小部件状态 + 打开认证 URL。</li><li><code>scripts/termux-auth-widget.sh</code>：完整的引导式小部件流程。</li><li><code>scripts/termux-sync-widget.sh</code>：同步 Claude Code 凭据 → OpenClaw。</li></ul><p>如果你不需要手机自动化或 systemd 定时器，请跳过这些脚本。</p>',11)])])}]]);export{a as __pageData,o as default};
